const flowCore = require('../');

describe('jibo-flow-core', function(){
    it('should have Activity', function(){
        expect(flowCore.Activity).be.ok;
    });

    it('should have FlowRoot', function(){
        expect(flowCore.FlowRoot).be.ok;
    });

    it('should have FlowRootFactory', function(){
        expect(flowCore.FlowRootFactory).be.ok;
    });

    it('should have Procedure', function(){
        expect(flowCore.Procedure).be.ok;
    });

    it('should have Transition', function(){
        expect(flowCore.Transition).be.ok;
    });

    it('should have loaders', function(){
        expect(flowCore.loaders).be.ok;
        expect(flowCore.loaders).is.an.object;
    });

    it('should have GojsLoader', function(){
        expect(flowCore.loaders.GojsLoader).be.ok;
    });

    it('should have TreeLoader', function(){
        expect(flowCore.loaders.TreeLoader).be.ok;
    });
});